import { useCallback, useEffect, useRef, useState } from 'react';
import { DamPicker } from '../dam-picker';
import type {
  DamPickerConfig,
  DamPickerCallbacks,
  SelectedAsset,
  DamPickerError,
} from '../types';

/**
 * React hook for using the DamPicker
 *
 * @example
 * ```tsx
 * function ImageSelector() {
 *   const { open } = useDamPicker({ token: 'your-token' });
 *
 *   return (
 *     <button onClick={() => open({
 *       onSelect: (asset) => console.log(asset.url)
 *     })}>
 *       Choose Image
 *     </button>
 *   );
 * }
 * ```
 */
export function useDamPicker(config: DamPickerConfig) {
  const pickerRef = useRef<DamPicker | null>(null);
  const [isOpen, setIsOpen] = useState(false);

  // Store latest config in ref to avoid recreating callbacks
  const configRef = useRef(config);
  configRef.current = config;

  /**
   * Opens the picker with the provided callbacks
   */
  const open = useCallback((callbacks: Partial<DamPickerCallbacks> & { onSelect: (asset: SelectedAsset) => void }) => {
    // Create a new picker instance with combined config and callbacks
    pickerRef.current = new DamPicker({
      ...configRef.current,
      onSelect: (asset: SelectedAsset) => {
        setIsOpen(false);
        callbacks.onSelect(asset);
      },
      onCancel: () => {
        setIsOpen(false);
        callbacks.onCancel?.();
      },
      onError: (error: DamPickerError) => {
        setIsOpen(false);
        callbacks.onError?.(error);
      },
      onReady: callbacks.onReady,
    });

    setIsOpen(true);
    pickerRef.current.open();
  }, []);

  /**
   * Closes the picker
   */
  const close = useCallback(() => {
    pickerRef.current?.close();
    setIsOpen(false);
  }, []);

  /**
   * Cleanup on unmount
   */
  useEffect(() => {
    return () => {
      pickerRef.current?.destroy();
      pickerRef.current = null;
    };
  }, []);

  return {
    open,
    close,
    isOpen,
  };
}
