import { useEffect, useRef } from 'react';
import { DamPicker } from '../dam-picker';
import type { SelectedAsset, DamPickerError, DamPickerFilters } from '../types';

export interface DamPickerModalProps {
  /** Whether the picker modal is open */
  isOpen: boolean;

  /** Fluid API token */
  token: string;

  /** Called when user selects an asset */
  onSelect: (asset: SelectedAsset) => void;

  /** Called when user cancels/closes the picker */
  onCancel?: () => void;

  /** Called when an error occurs */
  onError?: (error: DamPickerError) => void;

  /** Called when the picker is ready */
  onReady?: () => void;

  /** Override the picker app URL (for local development) */
  baseUrl?: string;

  /** Z-index for the modal overlay */
  zIndex?: number;

  /** Filter options */
  filters?: DamPickerFilters;
}

/**
 * React component for the DamPicker modal (controlled mode)
 *
 * @example
 * ```tsx
 * function ImageSelector() {
 *   const [isOpen, setIsOpen] = useState(false);
 *
 *   return (
 *     <>
 *       <button onClick={() => setIsOpen(true)}>Choose Image</button>
 *       <DamPickerModal
 *         isOpen={isOpen}
 *         token="your-token"
 *         onSelect={(asset) => {
 *           console.log(asset.url);
 *           setIsOpen(false);
 *         }}
 *         onCancel={() => setIsOpen(false)}
 *       />
 *     </>
 *   );
 * }
 * ```
 */
export function DamPickerModal({
  isOpen,
  token,
  onSelect,
  onCancel,
  onError,
  onReady,
  baseUrl,
  zIndex,
  filters,
}: DamPickerModalProps) {
  const pickerRef = useRef<DamPicker | null>(null);
  const wasOpenRef = useRef(false);

  // Store callbacks in refs to avoid recreating picker on callback changes
  const callbacksRef = useRef({ onSelect, onCancel, onError, onReady });
  callbacksRef.current = { onSelect, onCancel, onError, onReady };

  useEffect(() => {
    // Only act on changes (not initial mount when isOpen is false)
    const wasOpen = wasOpenRef.current;
    wasOpenRef.current = isOpen;

    if (isOpen && !wasOpen) {
      // Opening: Create new picker instance
      pickerRef.current = new DamPicker({
        token,
        baseUrl,
        zIndex,
        filters,
        onSelect: (asset) => callbacksRef.current.onSelect(asset),
        onCancel: () => callbacksRef.current.onCancel?.(),
        onError: (error) => callbacksRef.current.onError?.(error),
        onReady: () => callbacksRef.current.onReady?.(),
      });
      pickerRef.current.open();
    } else if (!isOpen && wasOpen) {
      // Closing: Destroy picker
      pickerRef.current?.destroy();
      pickerRef.current = null;
    }
  }, [isOpen, token, baseUrl, zIndex, filters]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      pickerRef.current?.destroy();
      pickerRef.current = null;
    };
  }, []);

  // Component doesn't render anything - the picker renders its own overlay
  return null;
}
